define i1 @src_is_mask_const_sge(i8 %x_in) {
  %x = xor i8 %x_in, 123
  %and = and i8 %x, 31
  %r = icmp sge i8 %and, %x
  ret i1 %r
}

define i1 @src_x_and_nmask_sge(i8 %x, i8 %y) {
  %not_mask = shl i8 -1, %y
  %and = and i8 %x, %not_mask
  %r = icmp sge i8 %and, %not_mask
  ret i1 %r
}

define i1 @src_x_and_nmask_slt(i8 %x, i8 %y) {
  %not_mask = shl i8 -1, %y
  %and = and i8 %x, %not_mask
  %r = icmp slt i8 %and, %not_mask
  ret i1 %r
}
